package mhir.gen
package verilog

import mhir.debug.indent
import mhir.gen.verilog.{
  VerilogTestbenchInputGenerator => InGen,
  VerilogTestbenchOutputGenerator => OutGen
}
import os.Path

object VerilogTestbenchGenerator {

  /** Creates a testbench that tests the correctness of a Verilog design
    * generated by
    * [[https://dl.acm.org/doi/10.1145/3385412.3385983 Aetherling]].
    *
    * @param inputs
    *   the inputs to provide to the design.
    * @param expectedOutput
    *   the expected outputs.
    * @param dir
    *   the directory of the Verilog project.
    */
  def makeTestbench(
      io: TestIO,
      dir: Path
  ): Unit = {
    val code = getTestbenchCode(
      io.inputs.tchk().asInstanceOf[DirectTestInput],
      io.expectedOutput.tchk().asInstanceOf[DirectTestOutput]
    )
    emitTestbench(code, dir)
  }

  private def emitTestbench(code: String, dir: Path): Unit = {
    val f = dir / "Test.v"
    if (os.isFile(f)) os.remove(f)
    os.write(f, code)
  }

  private def getTestbenchCode(
      inputs: DirectTestInput,
      expectedOutput: DirectTestOutput
  ): String = {
    val portMap =
      getPortMap(InGen.getNames(inputs), OutGen.getNames(expectedOutput))
    val inputDecls = InGen.getDirectInputDecls(inputs)
    val inputGenBlock = InGen.getBlock(inputs)
    val outputDecls = OutGen.getDecls(expectedOutput)
    val outputCheckBlock = OutGen.getBlock(expectedOutput)
    s"""`timescale 1ns/1ps
       |
       |module Test;
       |
       |    reg clock, reset, valid_up;
       |    wire valid_down;
       |    reg [31:0] t;
       |
       |${indent(inputDecls)}
       |
       |${indent(outputDecls)}
       |
       |${indent(portMap)}
       |
       |    task initialize ();
       |    begin
       |        $$display("Initializing design...");
       |        reset = 1;
       |        @(posedge clock) begin
       |            reset = 0;
       |        end
       |    end
       |    endtask
       |
       |    initial begin
       |        $$display("Started clock generator.");
       |        clock = 0;
       |        forever
       |            #10 clock = ~clock;
       |    end
       |
       |    initial begin
       |        $$display("Started clock counter.");
       |        // Start timing from the moment resetting is done
       |        @(negedge reset) begin
       |            t = 0;
       |        end
       |        forever begin
       |            @(posedge clock) begin
       |                t = t + 1;
       |            end
       |        end
       |    end
       |
       |${indent(inputGenBlock)}
       |
       |${indent(outputCheckBlock)}
       |
       |endmodule
       |""".stripMargin
  }

  private def getPortMap(
      inputNames: Seq[String],
      outputNames: Seq[String]
  ): String = {
    val inputPortMappings = inputNames.map(i => s".$i($i)").mkString(", ")
    val outputPortMappings = outputNames.map(o => s".$o($o)").mkString(", ")
    s"""Top DUT (
       |    .clock(clock),
       |    .reset(reset),
       |    .valid_up(valid_up),
       |    .valid_down(valid_down),
       |    $inputPortMappings,
       |    $outputPortMappings
       |);
       |""".stripMargin.stripTrailing
  }
}
